import { ethers } from "ethers";

const ERC20_ABI = [
  "function approve(address spender, uint256 amount) external returns (bool)",
  "function allowance(address owner, address spender) external view returns (uint256)",
  "function balanceOf(address account) external view returns (uint256)",
  "function decimals() external view returns (uint8)",
  "function symbol() external view returns (string)",
  "function name() external view returns (string)"
];

const ROUTER_ABI = [
  "function swapExactTokensForTokens(uint256 amountIn,uint256 amountOutMin,address[] calldata path,address to,uint256 deadline) external returns (uint256[] memory amounts)",
  "function getAmountsOut(uint256 amountIn,address[] calldata path) external view returns (uint256[] memory amounts)"
];

const MAX_UINT256 = ethers.MaxUint256;

export class TokenSwapDApp {
  constructor({
    provider,
    routerAddress,
    account = null
  }) {
    this.provider = provider;
    this.routerAddress = routerAddress;
    this.account = account;
    this.signer = null;
    this.router = null;
  }

  async init() {
    if (!this.provider) {
      if (typeof window !== "undefined" && window.ethereum) {
        this.provider = new ethers.BrowserProvider(window.ethereum);
      } else {
        throw new Error("No provider available");
      }
    }

    if (!this.account) {
      const accounts = await this.provider.send("eth_requestAccounts", []);
      this.account = accounts[0];
    }

    this.signer = await this.provider.getSigner();
    this.router = new ethers.Contract(this.routerAddress, ROUTER_ABI, this.signer);
    return this;
  }

  getERC20(tokenAddress, withSigner = true) {
    const runner = withSigner ? this.signer : this.provider;
    return new ethers.Contract(tokenAddress, ERC20_ABI, runner);
  }

  async getTokenMetadata(tokenAddress) {
    const token = this.getERC20(tokenAddress, false);
    const [name, symbol, decimals] = await Promise.all([
      token.name(),
      token.symbol(),
      token.decimals()
    ]);
    return { address: tokenAddress, name, symbol, decimals: Number(decimals) };
  }

  async getBalance(tokenAddress, owner = this.account) {
    const token = this.getERC20(tokenAddress, false);
    return await token.balanceOf(owner);
  }

  async getAllowance(tokenAddress, owner = this.account, spender = this.routerAddress) {
    const token = this.getERC20(tokenAddress, false);
    return await token.allowance(owner, spender);
  }

  async needsApproval(tokenAddress, amount, owner = this.account, spender = this.routerAddress) {
    const allowance = await this.getAllowance(tokenAddress, owner, spender);
    return allowance < amount;
  }

  async approveMax(tokenAddress, spender = this.routerAddress) {
    const token = this.getERC20(tokenAddress, true);
    const tx = await token.approve(spender, MAX_UINT256);
    const receipt = await tx.wait();
    return { tx, receipt, approvedAmount: MAX_UINT256 };
  }

  async ensureApproval(tokenAddress, amount, spender = this.routerAddress) {
    const required = ethers.getBigInt(amount);
    const approvalNeeded = await this.needsApproval(tokenAddress, required, this.account, spender);

    if (!approvalNeeded) {
      return { approved: false, alreadySufficient: true };
    }

    const result = await this.approveMax(tokenAddress, spender);
    return { approved: true, alreadySufficient: false, ...result };
  }

  async quoteSwap(amountIn, path) {
    const amounts = await this.router.getAmountsOut(amountIn, path);
    return amounts;
  }

  async swapExactTokensForTokens({
    tokenIn,
    tokenOut,
    amountIn,
    amountOutMin,
    to = this.account,
    deadlineSecondsFromNow = 1200,
    path = null,
    autoApprove = true
  }) {
    const swapPath = path || [tokenIn, tokenOut];
    const normalizedAmountIn = ethers.getBigInt(amountIn);
    const normalizedAmountOutMin = ethers.getBigInt(amountOutMin);
    const deadline = Math.floor(Date.now() / 1000) + deadlineSecondsFromNow;

    let approvalResult = null;
    if (autoApprove) {
      approvalResult = await this.ensureApproval(tokenIn, normalizedAmountIn, this.routerAddress);
    }

    const tx = await this.router.swapExactTokensForTokens(
      normalizedAmountIn,
      normalizedAmountOutMin,
      swapPath,
      to,
      deadline
    );

    const receipt = await tx.wait();

    return {
      approvalResult,
      tx,
      receipt
    };
  }

  async parseAmount(tokenAddress, humanReadableAmount) {
    const token = this.getERC20(tokenAddress, false);
    const decimals = await token.decimals();
    return ethers.parseUnits(String(humanReadableAmount), decimals);
  }

  async formatAmount(tokenAddress, rawAmount) {
    const token = this.getERC20(tokenAddress, false);
    const decimals = await token.decimals();
    return ethers.formatUnits(rawAmount, decimals);
  }
}

export async function createSwapApp(routerAddress) {
  const app = new TokenSwapDApp({ routerAddress });
  await app.init();
  return app;
}

export async function exampleUsage() {
  const routerAddress = "0xRouterAddressHere";
  const tokenIn = "0xTokenInAddressHere";
  const tokenOut = "0xTokenOutAddressHere";

  const app = await createSwapApp(routerAddress);

  const amountIn = await app.parseAmount(tokenIn, "1.0");
  const quote = await app.quoteSwap(amountIn, [tokenIn, tokenOut]);
  const amountOutMin = (quote[quote.length - 1] * 95n) / 100n;

  return await app.swapExactTokensForTokens({
    tokenIn,
    tokenOut,
    amountIn,
    amountOutMin,
    autoApprove: true
  });
}